// Temp helper: call a tool on mcp-memory.js over stdio JSON-RPC.
// Usage: node mcp-call.mjs <toolName> '<jsonArgs>'
import { spawn } from 'node:child_process';

const [tool, argsJson] = process.argv.slice(2);
const args = argsJson ? JSON.parse(argsJson) : {};

const child = spawn('node', ['G:\\AI\\telegram-kiro-bridge-main\\dist\\mcp-memory.js'], {
  env: { ...process.env, MEMORY_USER_ID: '509424983', MEMORY_DIR: 'G:\\AI\\AIMemory' },
  stdio: ['pipe', 'pipe', 'inherit'],
});

let buf = '';
const send = (obj) => child.stdin.write(JSON.stringify(obj) + '\n');

child.stdout.on('data', (d) => {
  buf += d.toString();
  let idx;
  while ((idx = buf.indexOf('\n')) >= 0) {
    const line = buf.slice(0, idx).trim();
    buf = buf.slice(idx + 1);
    if (!line) continue;
    let msg;
    try { msg = JSON.parse(line); } catch { continue; }
    if (msg.id === 1) {
      send({ jsonrpc: '2.0', method: 'notifications/initialized' });
      send({ jsonrpc: '2.0', id: 2, method: 'tools/call', params: { name: tool, arguments: args } });
    } else if (msg.id === 2) {
      console.log(JSON.stringify(msg, null, 2));
      child.kill();
      process.exit(msg.error ? 1 : 0);
    }
  }
});

send({
  jsonrpc: '2.0', id: 1, method: 'initialize',
  params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'curate-helper', version: '1.0' } },
});

setTimeout(() => { console.error('timeout'); child.kill(); process.exit(1); }, 30000);

